function a(t){return new Intl.NumberFormat("zh-CN").format(t)}function u(t){return t<=0?"0s":`${(t/1e3).toFixed(1)}s`}function c(t,e){return e<=0?"0%":`${Math.round(t/e*100)}%`}function o(t){if(!t)return"-";const e=new Date(t);if(Number.isNaN(e.getTime()))return t;const n=r=>String(r).padStart(2,"0");return`${e.getFullYear()}-${n(e.getMonth()+1)}-${n(e.getDate())} ${n(e.getHours())}:${n(e.getMinutes())}:${n(e.getSeconds())}`}function s(t){return t<500?"stats-latency-good":t<2e3?"stats-latency-warn":"stats-latency-bad"}export{o as a,a as b,c,u as f,s as l};
